sql:
SELECT AVG(absorbance_value) AS average_absorbance
FROM absorbance_readings
WHERE test_tube_id = 0;

SELECT operator_id, COUNT(*) AS total_readings
FROM absorbance_readings
GROUP BY operator_id;

SELECT COUNT(*) AS total_audits
FROM experiment_audits
WHERE user_id = 1;

SELECT absorbance_value
FROM absorbance_readings
WHERE test_tube_id = 1;

SELECT SUM(quantity) AS total_quantity
FROM chemical_inventory
WHERE chemical_id = 0;

SELECT description
FROM safety_protocols
WHERE safety_protocol_id = 1;
